P loadOrderTextSfl...
P                 B
D loadOrderTextSfl...
D                 PI
D*----------------------------------------------------------------
  *IN90 = *Off;
  *IN99 = *On;
  ZLA = 0;
  Write HS1212CA;
  *IN99 = *OFF;
  DATTXT = DATTX5;
  DATTOP = DATTO5;

  Chain(N) KEYGPS2 HSGPSPR;
  DOW Not %EoF(HSGPSPF);
      If GPS020 = *Blanks And GPS040 = 'TXT';
         MARKA = *Blanks;
         DATA  = *Blanks;
         DAT5  = %Char(GPS150);
         DAT6  = GPS080;
         If %Subst(GPS080:1:1) <> '+';
            ZLA += 1;
            Write HS1212SA;
          EndIf;
      EndIf;
      ReadE(N) KEYGPS2 HSGPSPR;
  EndDo;

  If ZLA <> 0;
     *In90 = *On;
     *In95 = *On;
     Write HS1212WA;
     ExFmt HS1212CA;
     *In90 = *Off;
     *In95 = *Off;

     If Not *In12;
         countZ = 0;
         ReadC HS1212SA;
         DoW Not %EoF(HS1212D);
             If MARKA <> *Blanks;
                countZ += 1;
                Chain countZ HS1212ST;
                If Not %EoF(HS1212D);
                   TEXT = DAT6;
                   Update HS1212ST;
                EndIf;
             EndIf;
             ReadC HS1212SA;
         EndDo;
         loadTextFromSfl();
     EndIf;
  EndIf;
  *In12 = *Off;
P                 E
